CREATE TABLE `product_issues` (
  `id` bigint(20) unsigned NOT NULL AUTO_INCREMENT,
  `purchase_order_id` varchar(255) DEFAULT NULL,
  `vendor_pi_id` varchar(255) DEFAULT NULL,
  `vendor_pi_product_id` varchar(255) DEFAULT NULL,
  `vendor_sku_code` varchar(255) DEFAULT NULL,
  `quantity_requirement` varchar(255) DEFAULT NULL,
  `available_quantity` varchar(255) DEFAULT NULL,
  `quantity_received` varchar(255) DEFAULT '0',
  `issue_item` varchar(255) NOT NULL DEFAULT '0',
  `issue_reason` varchar(255) DEFAULT NULL,
  `issue_description` varchar(255) DEFAULT NULL,
  `issue_from` enum('warehouse','vendor') DEFAULT NULL COMMENT 'warehouse - Issue generated from warehouse for customer order, vendor - Issue generated from warehouse for vendors received purchase order',
  `issue_status` enum('pending','return','accept','completed') DEFAULT 'pending' COMMENT 'pending, return, accept,completed',
  `created_at` timestamp NULL DEFAULT NULL,
  `updated_at` timestamp NULL DEFAULT NULL,
  PRIMARY KEY (`id`)
) ENGINE=InnoDB DEFAULT CHARSET=utf8mb4 COLLATE=utf8mb4_unicode_ci;
