/*!40101 SET character_set_client = utf8 */;
CREATE TABLE `warehouse_allocations` (
  `id` bigint(20) unsigned NOT NULL AUTO_INCREMENT,
  `rts_count_id` int(11) DEFAULT NULL COMMENT 'Ready to ship admin approval count id.',
  `sales_order_id` bigint(20) unsigned NOT NULL,
  `sales_order_product_id` bigint(20) unsigned NOT NULL,
  `customer_id` varchar(255) DEFAULT NULL COMMENT 'Customer id for the allocation.',
  `warehouse_id` bigint(20) unsigned NOT NULL,
  `sku` varchar(255) NOT NULL,
  `allocated_quantity` int(11) NOT NULL DEFAULT 0,
  `final_dispatched_quantity` int(11) DEFAULT NULL COMMENT 'Final quantity dispatched after packaging',
  `final_final_dispatched_quantity` int(11) DEFAULT NULL,
  `box_count` double DEFAULT NULL,
  `weight` double DEFAULT NULL,
  `sequence` int(11) NOT NULL DEFAULT 1 COMMENT 'Allocation sequence: 1 for first warehouse, 2 for second, etc.',
  `status` enum('pending','allocated','fulfilled','cancelled') NOT NULL DEFAULT 'pending',
  `approval_status` enum('draft','pending','approved','rejected') DEFAULT 'draft',
  `product_status` enum('pending','packaging','partially_packaged','approval_pending','packaged','completed','cancelled') DEFAULT 'pending',
  `shipping_status` enum('ready_to_ship','shipped','delivered','completed') NOT NULL DEFAULT 'ready_to_ship' COMMENT 'Shipping status for this warehouse allocation',
  `notes` text DEFAULT NULL,
  `created_at` timestamp NULL DEFAULT NULL,
  `updated_at` timestamp NULL DEFAULT NULL,
  `approved_by` bigint(20) unsigned DEFAULT NULL,
  `approved_at` timestamp NULL DEFAULT NULL,
  PRIMARY KEY (`id`),
  KEY `warehouse_allocations_sales_order_product_id_foreign` (`sales_order_product_id`),
  KEY `warehouse_allocations_sales_order_id_sku_index` (`sales_order_id`,`sku`),
  KEY `warehouse_allocations_warehouse_id_sku_index` (`warehouse_id`,`sku`),
  KEY `warehouse_allocations_status_index` (`status`),
  KEY `warehouse_allocations_approved_by_foreign` (`approved_by`),
  CONSTRAINT `warehouse_allocations_approved_by_foreign` FOREIGN KEY (`approved_by`) REFERENCES `users` (`id`) ON DELETE SET NULL,
  CONSTRAINT `warehouse_allocations_sales_order_id_foreign` FOREIGN KEY (`sales_order_id`) REFERENCES `sales_orders` (`id`) ON DELETE CASCADE,
  CONSTRAINT `warehouse_allocations_sales_order_product_id_foreign` FOREIGN KEY (`sales_order_product_id`) REFERENCES `sales_order_products` (`id`) ON DELETE CASCADE,
  CONSTRAINT `warehouse_allocations_warehouse_id_foreign` FOREIGN KEY (`warehouse_id`) REFERENCES `warehouses` (`id`) ON DELETE CASCADE
) ENGINE=InnoDB AUTO_INCREMENT=13 DEFAULT CHARSET=utf8mb4 COLLATE=utf8mb4_unicode_ci;
